import { useEffect, useRef } from "react";
import * as THREE from "three";

export default function CinematicIntro() {
  const containerRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        if (!containerRef.current) return;

            // SCENE
                const scene = new THREE.Scene();
                    scene.background = new THREE.Color(0x000000);
                        scene.fog = new THREE.Fog(0x000000, 40, 300);

                            // CAMERA
                                const camera = new THREE.PerspectiveCamera(
                                      70,
                                            window.innerWidth / window.innerHeight,
                                                  0.1,
                                                        1000
                                                            );

                                                                camera.position.set(0, 15, 220);

                                                                    // RENDERER
                                                                        const renderer = new THREE.WebGLRenderer({
                                                                              antialias: true,
                                                                                    powerPreference: "high-performance",
                                                                                        });

                                                                                            renderer.setSize(window.innerWidth, window.innerHeight);
                                                                                                renderer.setPixelRatio(window.devicePixelRatio);

                                                                                                    containerRef.current.appendChild(renderer.domElement);

                                                                                                        // LUZ AMBIENTE
                                                                                                            const ambientLight = new THREE.AmbientLight(0xffffff, 0.3);
                                                                                                                scene.add(ambientLight);

                                                                                                                    // HOLOFOTE PRINCIPAL
                                                                                                                        const spotLight = new THREE.SpotLight(0xffd700, 6, 300, Math.PI / 4, 0.5, 1);
                                                                                                                            spotLight.position.set(0, 80, 40);
                                                                                                                                scene.add(spotLight);

                                                                                                                                    // LUZ NEON
                                                                                                                                        const neonLight = new THREE.PointLight(0x00eaff, 2, 120);
                                                                                                                                            neonLight.position.set(0, -8, 20);
                                                                                                                                                scene.add(neonLight);

                                                                                                                                                    // GRUPO LETREIRO
                                                                                                                                                        const signGroup = new THREE.Group();
                                                                                                                                                            scene.add(signGroup);

                                                                                                                                                                // CANVAS DO LETREIRO
                                                                                                                                                                    const canvas = document.createElement("canvas");
                                                                                                                                                                        canvas.width = 2048;
                                                                                                                                                                            canvas.height = 512;

                                                                                                                                                                                const ctx = canvas.getContext("2d");

                                                                                                                                                                                    if (ctx) {
                                                                                                                                                                                          ctx.fillStyle = "#050505";
                                                                                                                                                                                                ctx.fillRect(0, 0, canvas.width, canvas.height);

                                                                                                                                                                                                      ctx.font = '900 170px "Impact", "Arial Black", sans-serif';
                                                                                                                                                                                                            ctx.textAlign = "center";
                                                                                                                                                                                                                  ctx.textBaseline = "middle";

                                                                                                                                                                                                                        const gradient = ctx.createLinearGradient(0, 100, 0, 400);
                                                                                                                                                                                                                              gradient.addColorStop(0, "#fff6b0");
                                                                                                                                                                                                                                    gradient.addColorStop(0.5, "#ffd700");
                                                                                                                                                                                                                                          gradient.addColorStop(1, "#8b6b2c");

                                                                                                                                                                                                                                                ctx.shadowColor = "#00eaff";
                                                                                                                                                                                                                                                      ctx.shadowBlur = 40;

                                                                                                                                                                                                                                                            ctx.fillStyle = gradient;

                                                                                                                                                                                                                                                                  ctx.fillText(
                                                                                                                                                                                                                                                                          "COMPLEXO DO COMANDO NORTE",
                                                                                                                                                                                                                                                                                  canvas.width / 2,
                                                                                                                                                                                                                                                                                          canvas.height / 2
                                                                                                                                                                                                                                                                                                );
                                                                                                                                                                                                                                                                                                    }

                                                                                                                                                                                                                                                                                                        const texture = new THREE.CanvasTexture(canvas);

                                                                                                                                                                                                                                                                                                            const signMaterial = new THREE.MeshStandardMaterial({
                                                                                                                                                                                                                                                                                                                  map: texture,
                                                                                                                                                                                                                                                                                                                        metalness: 1,
                                                                                                                                                                                                                                                                                                                              roughness: 0.2,
                                                                                                                                                                                                                                                                                                                                    emissive: new THREE.Color(0xffd700),
                                                                                                                                                                                                                                                                                                                                          emissiveIntensity: 0.7,
                                                                                                                                                                                                                                                                                                                                              });

                                                                                                                                                                                                                                                                                                                                                  const signMesh = new THREE.Mesh(
                                                                                                                                                                                                                                                                                                                                                        new THREE.PlaneGeometry(60, 15),
                                                                                                                                                                                                                                                                                                                                                              signMaterial
                                                                                                                                                                                                                                                                                                                                                                  );

                                                                                                                                                                                                                                                                                                                                                                      signGroup.add(signMesh);

                                                                                                                                                                                                                                                                                                                                                                          // MOLDURA
                                                                                                                                                                                                                                                                                                                                                                              const frame = new THREE.Mesh(
                                                                                                                                                                                                                                                                                                                                                                                    new THREE.BoxGeometry(64, 19, 1),
                                                                                                                                                                                                                                                                                                                                                                                          new THREE.MeshStandardMaterial({
                                                                                                                                                                                                                                                                                                                                                                                                  color: 0xffd700,
                                                                                                                                                                                                                                                                                                                                                                                                          metalness: 1,
                                                                                                                                                                                                                                                                                                                                                                                                                  roughness: 0.2,
                                                                                                                                                                                                                                                                                                                                                                                                                        })
                                                                                                                                                                                                                                                                                                                                                                                                                            );

                                                                                                                                                                                                                                                                                                                                                                                                                                frame.position.z = -0.5;

                                                                                                                                                                                                                                                                                                                                                                                                                                    signGroup.add(frame);

                                                                                                                                                                                                                                                                                                                                                                                                                                        // PARTÍCULAS (POEIRA)
                                                                                                                                                                                                                                                                                                                                                                                                                                            const particleCount = 1200;

                                                                                                                                                                                                                                                                                                                                                                                                                                                const particles = new THREE.BufferGeometry();

                                                                                                                                                                                                                                                                                                                                                                                                                                                    const positions = new Float32Array(particleCount * 3);

                                                                                                                                                                                                                                                                                                                                                                                                                                                        for (let i = 0; i < particleCount; i++) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                              positions[i * 3] = (Math.random() - 0.5) * 200;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                    positions[i * 3 + 1] = Math.random() * 80 - 20;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                          positions[i * 3 + 2] = (Math.random() - 0.5) * 200;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                              }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  particles.setAttribute(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        "position",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              new THREE.BufferAttribute(positions, 3)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  );

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      const particleMaterial = new THREE.PointsMaterial({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            color: 0xffffff,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  size: 0.7,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        transparent: true,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              opacity: 0.6,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  });

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      const particleSystem = new THREE.Points(particles, particleMaterial);

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          scene.add(particleSystem);

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              // ANIMAÇÃO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  const startTime = Date.now();

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      const introDuration = 6000;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          const animate = () => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                requestAnimationFrame(animate);

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      const elapsed = Date.now() - startTime;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            if (elapsed < introDuration) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const progress = elapsed / introDuration;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            const ease = 1 - Math.pow(1 - progress, 4);

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    camera.position.z = 220 - ease * 180;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            camera.position.y = 15 - ease * 12;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    signGroup.position.y = -10 + ease * 10;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            neonLight.intensity = 1.5 + Math.sin(elapsed * 0.005) * 2;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  } else {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          camera.position.x = Math.sin(elapsed * 0.002) * 0.15;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  camera.position.y = 3 + Math.cos(elapsed * 0.002) * 0.15;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              signGroup.rotation.y = Math.sin(elapsed * 0.001) * 0.04;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    particleSystem.rotation.y += 0.0005;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          renderer.render(scene, camera);

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                // TRANSIÇÃO PARA O JOGO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      if (elapsed > 9000) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              document.body.style.transition = "opacity 1.5s";
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      document.body.style.opacity = "0";

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              setTimeout(() => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        window.location.href = "/game";
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }, 1500);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          };

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              animate();

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  // RESIZE
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      const handleResize = () => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            camera.aspect = window.innerWidth / window.innerHeight;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  camera.updateProjectionMatrix();

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        renderer.setSize(window.innerWidth, window.innerHeight);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            };

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                window.addEventListener("resize", handleResize);

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    return () => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          window.removeEventListener("resize", handleResize);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                renderer.dispose();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    };
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      }, []);

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        return (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  ref={containerRef}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        style={{
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                width: "100vw",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        height: "100vh",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                background: "#000",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        overflow: "hidden",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              }}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }
